import React, { useState, useEffect } from 'react';
import axios from 'axios';

const App = () => {
  const [users, setUsers] = useState([]);
  const [name, setName] = useState('');
  const [id, setId] = useState('');

  useEffect(() => {
    axios.get('http://localhost:3001/users')
      .then(response => setUsers(response.data))
      .catch(error => console.error(error));
  }, []);

  const addUser = () => {
    axios.post('http://localhost:3001/add-user', { id, name })
      .then(() => {
        setUsers([...users, { id, name }]);
        setId('');
        setName('');
      })
      .catch(error => console.error(error));
  };

  const checkFingerprint = () => {
    axios.post('http://localhost:3001/check-fingerprint', { id })
      .then(response => alert(response.data))
      .catch(error => alert(error.response.data));
  };

  return (
    <div>
      <h1>User Management</h1>
      <input
        type="text"
        value={id}
        onChange={(e) => setId(e.target.value)}
        placeholder="ID"
      />
      <input
        type="text"
        value={name}
        onChange={(e) => setName(e.target.value)}
        placeholder="Name"
      />
      <button onClick={addUser}>Add User</button>
      <button onClick={checkFingerprint}>Check Fingerprint</button>
      <ul>
        {users.map(user => (
          <li key={user.id}>{user.name} (ID: {user.id})</li>
        ))}
      </ul>
    </div>
  );
};

export default App;
